parameters.jsCode:
// Parsea la respuesta de Gemini (viene como texto JSON dentro de candidates[0].content.parts[0].text)
const response = $input.first().json;
let datos;
try {
  const rawText = response.candidates[0].content.parts[0].text;
  datos = JSON.parse(rawText);
} catch (e) {
  throw new Error('No se pudo parsear la respuesta de Gemini: ' + e.message);
}

const cloudinaryUrl = $node["Cloudinary - Subir Imagen"].json.secure_url || null;

return [{
  json: {
    numero_cheque: datos.numero_cheque,
    banco_emisor: datos.banco_emisor,
    cliente_razon_social: datos.cliente_razon_social,
    cuit: datos.cuit,
    monto: datos.monto,
    fecha_emision: datos.fecha_emision,
    fecha_vencimiento: datos.fecha_vencimiento,
    confianza_ia: datos.confianza,
    inconsistencia: datos.inconsistencia,
    observaciones: datos.observaciones,
    imagen_url: cloudinaryUrl,
    datos_ia: datos
  }
}];
